const item = $input.first().json;
const order = item.order || {};
const text = item.text || {};
const bible = text.bible || {};
const firstChapter = text.chapters?.[0] || {};
const chaptersTarget = Math.max(1, Math.min(8, Number(order.chapters || bible.chapterPlan?.length || 5)));
const laterNumbers = Array.from({ length: Math.max(0, chaptersTarget - 1) }, (_, index) => index + 2);
const chapterPlan = Array.isArray(bible.chapterPlan) ? bible.chapterPlan : [];
const laterPlan = laterNumbers.map((n) => {
  const planned = chapterPlan.find((chapter) => Number(chapter.n) === n) || { n, title: 'Глава ' + n, beat: '' };
  return { n, title: planned.title || ('Глава ' + n), beat: planned.beat || planned.summary || '' };
});
const heroes = (order.heroes || [])
  .filter((hero) => hero.name || hero.description || hero.relation)
  .map((hero) => 'Герой ' + hero.n + ': ' + (hero.name || 'без имени') + ' - ' + (hero.description || 'описание не задано') + ' - ' + (hero.relation || 'роль не задана'))
  .join('\n');
const style = order.illustrationStyle || 'storybook';
const worldBrief = [
  bible.worldTitle ? 'Название мира: ' + bible.worldTitle : '',
  bible.worldEnv ? 'Среда и законы: ' + bible.worldEnv : '',
  bible.worldMotifs ? 'Мотивы: ' + bible.worldMotifs : '',
  bible.worldConflict ? 'Конфликт: ' + bible.worldConflict : '',
  bible.worldVisual ? 'Визуальный язык: ' + bible.worldVisual : '',
].filter(Boolean).join('\n');
const firstChapterText = firstChapter.text || (Array.isArray(firstChapter.textBlocks) ? firstChapter.textBlocks.join('\n\n') : text.preview?.text || '');
const planText = laterPlan.map((chapter) => 'Глава ' + chapter.n + ': ' + chapter.title + '. Бит: ' + chapter.beat).join('\n');
const requestedShape = laterPlan.map((chapter) => '{ "n": ' + chapter.n + ', "title": "...", "summary": "...", "textBlocks": ["...", "...", "...", "...", "..."] }').join(', ');
const systemText = 'Ты - автор персональных книг Fairyteller. Пиши на русском языке, без буквы е с точками. Продолжай уже начатую историю строго по именам, отношениям, миру и фактам пользователя. Не добавляй известных copyrighted персонажей и не копируй чужие вселенные. Верни только валидный JSON, без markdown. Внутри JSON-строк не используй кавычки-елочки, списки и переносы строк; диалоги оформляй через тире.';
const userText = 'Нужно дописать персональную книгу после первой главы. Первая глава уже готова и будет показана пользователю сразу; сейчас напиши только главы 2-' + chaptersTarget + ', чтобы получилась цельная книга.\n\n' +
  'Название книги: ' + (bible.bookTitle || text.preview?.title || '') + '\n' +
  'Подзаголовок: ' + (bible.subtitle || '') + '\n' +
  'Обложечное резюме: ' + (bible.coverSummary || text.preview?.summary || '') + '\n' +
  'Мир:\n' + (worldBrief || order.world || '') + '\n\n' +
  'Место действия: ' + (order.location || bible.location || '') + '\n' +
  'Важный предмет/артефакт: ' + (order.artifact || bible.artifact || '') + '\n' +
  'Стиль иллюстраций для визуальной логики: ' + style + '\n\n' +
  'Персонажи:\n' + (heroes || 'Персонажи не заданы; продолжай по первой главе.') + '\n\n' +
  'Первая глава, которую нельзя переписывать:\n' + firstChapterText + '\n\n' +
  'План следующих глав:\n' + planText + '\n\n' +
  'Требования к главам 2-' + chaptersTarget + ': каждая глава должна иметь 5 текстовых блоков, каждый блок 450-750 знаков, без markdown, без нумерованных списков, с живыми сценами, диалогами и действием. Не пересказывай первую главу; продолжай сюжет. Финальная глава должна закрыть арку и дать теплое послевкусие.\n\n' +
  'Верни JSON строго такой формы: { "bookTitle": "...", "subtitle": "...", "coverSummary": "...", "chapters": [' + requestedShape + '] }';
const geminiRequest = {
  contents: [{ role: 'user', parts: [{ text: systemText + '\n\n' + userText }] }],
  generationConfig: {
    responseMimeType: 'application/json',
    temperature: 0.65,
    maxOutputTokens: 18000,
  },
};
return [{ json: { ...item, status: 'full_text_generating', laterPlan, fullTextPrompt: userText, geminiModel: 'gemini-2.5-flash', geminiRequest } }];

const source = $('Build Full Text Prompt').first().json;
const response = $input.first().json;
function collectText(value) {
  return String(value?.candidates?.[0]?.content?.parts?.map((part) => part.text || '').join('') || '').trim();
}
function extractJsonCandidate(text) {
  let candidate = String(text || '').trim().replace(/^\uFEFF/, '');
  const fence = candidate.match(/^\`\`\`(?:json)?\s*([\s\S]*?)\s*\`\`\`$/i);
  if (fence) candidate = fence[1].trim();
  const firstBrace = candidate.indexOf('{');
  const lastBrace = candidate.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) candidate = candidate.slice(firstBrace, lastBrace + 1);
  return candidate;
}
function escapeControlCharsInsideStrings(text) {
  let result = '';
  let inString = false;
  let escaped = false;
  for (const char of text) {
    if (escaped) { result += char; escaped = false; continue; }
    if (char === '\\') { result += char; escaped = true; continue; }
    if (char === '"') { inString = !inString; result += char; continue; }
    if (inString && char === '\n') { result += '\\n'; continue; }
    if (inString && char === '\r') { result += '\\r'; continue; }
    if (inString && char === '\t') { result += '\\t'; continue; }
    result += char;
  }
  return result;
}
function repairLikelyJson(text) {
  return String(text || '')
    .replace(/,\s*([}\]])/g, '$1')
    .replace(/"\s*\n\s*"/g, '"\n,"')
    .replace(/}\s*\n\s*"/g, '}\n,"')
    .replace(/]\s*\n\s*"/g, ']\n,"');
}
function parseGeminiJson(raw) {
  const candidate = extractJsonCandidate(raw);
  const escaped = escapeControlCharsInsideStrings(candidate);
  const attempts = [candidate, escaped, repairLikelyJson(escaped)];
  let lastError;
  for (const attempt of attempts) {
    try { return JSON.parse(attempt); } catch (error) { lastError = error; }
  }
  throw new Error('Gemini full-text response was not valid JSON after repair: ' + (lastError?.message || 'unknown parse error'));
}
const rawText = collectText(response);
if (!rawText) throw new Error('Gemini full-text response was empty');
const generated = parseGeminiJson(rawText);
const expectedNumbers = (source.laterPlan || []).map((chapter) => Number(chapter.n));
const laterChapters = Array.isArray(generated.chapters) ? generated.chapters : [];
const normalizedLater = laterChapters.map((chapter, index) => {
  const n = Number(chapter.n || expectedNumbers[index] || index + 2);
  const textBlocks = Array.isArray(chapter.textBlocks)
    ? chapter.textBlocks.map((block) => String(block || '').replace(/\s+/g, ' ').trim()).filter(Boolean)
    : ['text1','text2','text3','text4','text5'].map((key) => String(chapter[key] || '').replace(/\s+/g, ' ').trim()).filter(Boolean);
  if (textBlocks.length !== 5) throw new Error('Expected 5 text blocks for chapter ' + n + ', got ' + textBlocks.length);
  return {
    n,
    title: String(chapter.title || 'Глава ' + n).replace(/\s+/g, ' ').trim(),
    summary: String(chapter.summary || '').replace(/\s+/g, ' ').trim(),
    textBlocks,
    text: textBlocks.join('\n\n'),
    status: 'ready',
  };
}).filter((chapter) => expectedNumbers.includes(chapter.n));
if (normalizedLater.length !== expectedNumbers.length) {
  throw new Error('Expected later chapters ' + expectedNumbers.join(', ') + ', got ' + normalizedLater.map((chapter) => chapter.n).join(', '));
}
const firstChapter = source.text?.chapters?.[0];
if (!firstChapter) throw new Error('Missing first chapter from upstream text payload');
const chapters = [firstChapter, ...normalizedLater].sort((a, b) => Number(a.n) - Number(b.n));
const fullText = {
  bible: {
    ...(source.text?.bible || {}),
    bookTitle: generated.bookTitle || source.text?.bible?.bookTitle || '',
    subtitle: generated.subtitle || source.text?.bible?.subtitle || '',
    coverSummary: generated.coverSummary || source.text?.bible?.coverSummary || '',
  },
  preview: source.text?.preview || null,
  chapters,
  generation: {
    provider: 'gemini',
    model: source.geminiModel || 'gemini-2.5-flash',
    stage: 'full_text',
    responseId: response.responseId || null,
  },
};
return [{ json: { ...source, status: 'full_text_ready', text: fullText, fullText: { status: 'ready', chapterCount: chapters.length, laterChapterCount: normalizedLater.length } } }];
